It was certainly my preference to only allow the field class instead of the instance in `info`, but this makes supporting `Nested` and similar types impossible without adding some additional mechanism.

```python
        student = relationship(
            models.Student,
            info={
                'marshmallow_sqlalchemy': {
                    'field': fields.Nested(schemas.StudentSchema)
                 }
            }
        )
```

Actually, having read back through the marshmallow-sqlalchemy documentation I think it may be ok as it is. We just need to make it very clear that (as it does in the other documentation) that this is a field _override_.

class Errors(object):
    """Lazy loaded on request as 'errors'"""
    def add(location, name, description="", request=False):
      ...
      
def wrap(request):
    request.errors = Errors()
    return request
def my_checker(request):
    if 'X-Paid' not in request.headers:     
        request.errors.add('header', 'X-Paid', required=True)
    if 'limit' not in request.GET:
        request.errors.add('query', 'limit', required=True)
    if 'foo' in request.GET:
        try:
            request.validated['foo'] = int(foo)
        except ValueError:
            request.errors.add('query', 'foo', reason='wrong type')

